<?php
namespace app\Repositories; class BookTypeRepository extends BaseRepository{ public function all(string $q=''):array{return $q?$this->fetchAll("SELECT * FROM book_types WHERE name LIKE ? OR description LIKE ? ORDER BY id DESC",["%$q%","%$q%"]):$this->fetchAll("SELECT * FROM book_types ORDER BY id DESC");} public function find(int $id):?array{return $this->fetch("SELECT * FROM book_types WHERE id=?",[$id]);} public function create(array $d):int{$this->execute("INSERT INTO book_types(name,description) VALUES(?,?)",[$d['name'],$d['description']??null]);return $this->lastInsertId();} public function update(int $id,array $d):bool{return $this->execute("UPDATE book_types SET name=?,description=? WHERE id=?",[$d['name'],$d['description']??null,$id]);} public function delete(int $id):bool{return $this->execute("DELETE FROM book_types WHERE id=?",[$id]);} public function countBooks(int $id):int{return (int)$this->fetch("SELECT COUNT(*) c FROM books WHERE book_type_id=?",[$id])['c'];}}
